{# ===========================
   Customer Statement - PDF
   FIX 1: النوع reads from LMT Debt Collection
   FIX 2: ns.running scope fix
   FIX 3: POS shows bank account name (بطاقة الاسلامي etc.)
   =========================== #}

{% set from_date = "2000-01-01" %}
{% set to_date = (frappe.form_dict.get("to_date") or frappe.utils.nowdate()) %}

{% set party1 = (doc.customer_name or doc.name or "") %}
{% set party2 = (doc.name or doc.customer_name or "") %}

{% set company      = frappe.db.get_default("company") %}
{% set company_logo = frappe.db.get_value("Company", company, "company_logo") %}
{% set currency     = frappe.db.get_value("Company", company, "default_currency") %}

{% set gl_rows = frappe.db.sql("""
  SELECT
    posting_date, account, debit, credit,
    voucher_type, voucher_no, remarks, is_opening,
    (debit - credit) AS net
  FROM `tabGL Entry`
  WHERE docstatus=1 AND is_cancelled=0
    AND party_type='Customer'
    AND party IN (%s, %s)
    AND posting_date BETWEEN %s AND %s
  ORDER BY posting_date ASC, creation ASC
""", (party1, party2, from_date, to_date), as_dict=True) %}

{% set debt_rows = frappe.db.sql("""
  SELECT receipt_no, payment_type, mode_of_payment, name, bank
  FROM `tabLMT Debt Collection`
  WHERE docstatus < 2
    AND customer IN (%s, %s)
""", (party1, party2), as_dict=True) %}

{% set PAYMENT_DISPLAY = {
  "Cash":             "نقد",
  "Cheque":           "صك",
  "Bank Draft":       "صك",
  "Wire Transfer":    "تحويل",
  "POS terminal":     "ماكينة نقاط بيع",
  "Credit Card":      "تحويل",
  "نقد":              "نقد",
  "صك":               "صك",
  "تحويل":            "تحويل",
  "ماكينة نقاط بيع": "ماكينة نقاط بيع"
} %}

{% set ns = namespace(
    calc_opening   = 0.0,
    calc_movement  = 0.0,
    total_sale     = 0.0,
    total_collect  = 0.0,
    running        = 0.0,
    debt_map       = {}
) %}

{# Build debt_map — POS: use bank field, strip " - XX" suffix #}
{% for d in debt_rows %}
  {% set raw = (d.payment_type or d.mode_of_payment or "") %}
  {% if raw == "ماكينة نقاط بيع" or raw == "POS terminal" %}
    {% set bank_raw = (d.bank or "ماكينة نقاط بيع") %}
    {% set label = bank_raw.rsplit(" - ", 1)[0].strip() %}
  {% else %}
    {% set label = PAYMENT_DISPLAY.get(raw, raw) %}
  {% endif %}
  {% if d.receipt_no %}
    {% set _ = ns.debt_map.update({ (d.receipt_no)|string : label }) %}
  {% endif %}
  {% set _ = ns.debt_map.update({ (d.name)|string : label }) %}
{% endfor %}

{% set sql_opening = frappe.db.sql("""
  SELECT IFNULL(SUM(debit - credit), 0) AS opening
  FROM `tabGL Entry`
  WHERE docstatus=1 AND is_cancelled=0
    AND party_type='Customer'
    AND party IN (%s, %s)
    AND posting_date < %s
""", (party1, party2, from_date), as_dict=True)[0] %}

{% set ns.calc_opening = (sql_opening.opening or 0) | float %}

{% for r in gl_rows %}
  {% set net        = (r.net or 0) | float %}
  {% set remark_low = (r.remarks or "")|string|lower %}
  {% if r.is_opening == "Yes" or r.is_opening == 1 or "migration" in remark_low or "opening" in remark_low or "افتتاحي" in remark_low %}
    {% set ns.calc_opening = ns.calc_opening + net %}
  {% else %}
    {% set ns.calc_movement = ns.calc_movement + net %}
  {% endif %}
{% endfor %}

{% set closing = ns.calc_opening + ns.calc_movement %}

<link href="https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;900&display=swap" rel="stylesheet">

<style>
  @page { size: A4 portrait; margin: 10mm; }
  .print-format { font-family: 'Cairo', sans-serif !important; direction: rtl; color: #000; font-size: 11px; padding: 0 !important; }
  .hdr { text-align: center; margin-bottom: 10px; }
  .header-logo { width: 100%; max-height: 95px; object-fit: contain; display: block; margin: 0 auto 6px; }
  .meta { font-size: 12px; margin-top: 4px; }
  .info { width: 100%; border-collapse: collapse; margin: 8px 0 10px; }
  .info td { padding: 4px; vertical-align: top; }
  .box { border: 1px solid #000; border-radius: 8px; padding: 8px 10px; }
  .num { direction: ltr; text-align: left; display: inline-block; min-width: 90px; font-weight: 900; }
  table.tbl { width: 100%; border-collapse: collapse; border: 1px solid #000; margin-top: 8px; table-layout: fixed; }
  .tbl th, .tbl td { border: 1px solid #000; padding: 6px; text-align: center; vertical-align: middle; word-break: break-word; }
  .tbl th { background: #f2f2f2; font-weight: 900; -webkit-print-color-adjust: exact; }
  .right { text-align: right !important; }
  .sum { margin-top: 12px; width: 100%; border-collapse: collapse; border: 2px solid #000; }
  .sum td { border: 1px solid #000; padding: 10px; font-weight: 900; font-size: 13px; text-align: center; background: #eee; -webkit-print-color-adjust: exact; }
  .footer { text-align: center; margin-top: 22px; font-size: 11px; border-top: 1px solid #000; padding-top: 10px; }
</style>

<div class="print-format">

  <div class="hdr">
    {% if company_logo %}
      <img class="header-logo" src="{{ frappe.utils.get_url() }}{{ company_logo }}">
    {% endif %}
    <div style="font-size:20px; font-weight:900; text-decoration:underline;">كشف حساب الزبون</div>
    <div class="meta">من: 01-01-2022 — إلى: {{ frappe.utils.formatdate(to_date) }}</div>
    <div class="meta">تاريخ إصدار الكشف: {{ frappe.utils.formatdate(frappe.utils.nowdate()) }}</div>
  </div>

  <table class="info">
    <tr>
      <td style="width:55%;">
        <div class="box right">
          <div><strong>الزبون:</strong> {{ doc.customer_name or doc.name }}</div>
          <div>
            <strong>المندوب:</strong>
            {% set am = doc.account_manager %}
            {% if am %}
              {{ frappe.db.get_value("User", am, "full_name") or frappe.utils.get_fullname(am) or am }}
            {% else %}
              غير محدد
            {% endif %}
          </div>
          <div><strong>العنوان:</strong> {{ doc.customer_primary_address or doc.primary_address or "غير محدد" }}</div>
        </div>
      </td>
      <td style="width:45%;">
        <div class="box">
          <div><strong>الرصيد الافتتاحي:</strong> <span class="num">{{ frappe.utils.fmt_money(ns.calc_opening, currency=currency) }}</span></div>
          <div><strong>الحركة:</strong>            <span class="num">{{ frappe.utils.fmt_money(ns.calc_movement, currency=currency) }}</span></div>
          <div><strong>الرصيد النهائي:</strong>     <span class="num">{{ frappe.utils.fmt_money(closing, currency=currency) }}</span></div>
        </div>
      </td>
    </tr>
  </table>

  <table class="tbl">
    <colgroup>
      <col style="width:11%"><col style="width:17%"><col style="width:12%">
      <col style="width:10%"><col style="width:12%"><col style="width:13%"><col style="width:14%">
    </colgroup>
    <thead>
      <tr>
        <th>التاريخ</th><th>رقم الفاتورة</th><th>البيع</th>
        <th>الايصال</th><th>التحصيل</th><th>النوع</th><th>الرصيد</th>
      </tr>
    </thead>
    <tbody>

      {% set ns.running = (sql_opening.opening or 0) | float %}

      {% if ns.running != 0 %}
        <tr>
          <td>--</td><td class="right">رصيد سابق</td>
          <td></td><td></td><td></td><td></td>
          <td><strong>{{ frappe.utils.fmt_money(ns.running, currency=currency) }}</strong></td>
        </tr>
      {% endif %}

      {% for r in gl_rows %}
        {% set net  = (r.net or 0) | float %}
        {% set sale = (net if net > 0 else 0) | float %}
        {% set col  = ((-net) if net < 0 else 0) | float %}

        {% set ns.running       = (ns.running + net) | float %}
        {% set ns.total_sale    = ns.total_sale    + sale %}
        {% set ns.total_collect = ns.total_collect + col  %}

        {% set vt         = (r.voucher_type or "") %}
        {% set remark_str = (r.remarks or "")|string %}
        {% set lremark    = remark_str|lower %}

        {% set vt_label = "قيد يومية" %}
        {% if "migration" in lremark or "opening" in lremark or "افتتاحي" in lremark %}
          {% set vt_label = "رصيد افتتاحي" %}
        {% elif vt == "Sales Invoice" %}
          {% set vt_label = "فاتورة" %}
        {% elif vt == "Payment Entry" %}
          {% set vt_label = "سند قبض" %}
        {% endif %}

        {# ── RECEIPT EXTRACTION ── #}
        {% set display_ref = "" %}
        {% if "||" in remark_str %}
          {% set display_ref = remark_str.split("||")[0].strip() %}
        {% endif %}
        {% if display_ref == "" and "إشارة عملية لا" in remark_str %}
          {% set tail = remark_str.split("إشارة عملية لا")[1].strip() %}
          {% if "بتاريخ" in tail %}
            {% set display_ref = tail.split("بتاريخ")[0].strip() %}
          {% else %}
            {% set display_ref = tail.split()[0] %}
          {% endif %}
        {% endif %}
        {% if display_ref == "" and "transaction reference no" in lremark %}
          {% set tail = lremark.split("transaction reference no")[1].strip() %}
          {% if "dated" in tail %}
            {% set display_ref = tail.split("dated")[0].strip() %}
          {% else %}
            {% set display_ref = tail.split()[0] %}
          {% endif %}
        {% endif %}
        {% if display_ref == "" and "reference no" in lremark and "transaction" not in lremark %}
          {% set tail = lremark.split("reference no")[1].strip() %}
          {% if "dated" in tail %}
            {% set display_ref = tail.split("dated")[0].strip() %}
          {% else %}
            {% set display_ref = tail.split()[0] %}
          {% endif %}
        {% endif %}
        {% if display_ref == "" and "واصل:" in remark_str %}
          {% set display_ref = remark_str.split("واصل:")[1].strip().split()[0] %}
        {% endif %}
        {% set display_ref = display_ref.replace("#", "").strip() %}

        {# ── LOOK UP النوع — POS shows bank account name ── #}
        {% if vt == "Payment Entry" and display_ref != "" %}
          {% set looked_up = ns.debt_map.get(display_ref, "") %}
          {% if looked_up != "" %}
            {% set vt_label = looked_up %}
          {% endif %}
        {% endif %}

        <tr>
          <td>{{ frappe.utils.formatdate(r.posting_date) }}</td>
          <td>{{ r.voucher_no or "" }}</td>
          <td>{% if sale > 0 %}{{ frappe.utils.fmt_money(sale, currency=currency) }}{% endif %}</td>
          <td>{{ display_ref }}</td>
          <td>{% if col > 0 %}{{ frappe.utils.fmt_money(col, currency=currency) }}{% endif %}</td>
          <td>{{ vt_label }}</td>
          <td><strong>{{ frappe.utils.fmt_money(ns.running, currency=currency) }}</strong></td>
        </tr>
      {% endfor %}

      {% if (gl_rows|length == 0) and (ns.running == 0) %}
        <tr><td colspan="7" style="padding:18px; text-align:center;">لا توجد بيانات</td></tr>
      {% endif %}

    </tbody>
  </table>

  <table class="sum">
    <tr>
      <td>مجموع البيع: {{ frappe.utils.fmt_money(ns.total_sale, currency=currency) }}</td>
      <td>مجموع التحصيل: {{ frappe.utils.fmt_money(ns.total_collect, currency=currency) }}</td>
      <td>الرصيد النهائي: {{ frappe.utils.fmt_money(closing, currency=currency) }}</td>
    </tr>
  </table>

  <div class="footer">
    للاستفسار الاتصال على الأرقام التالية : (0926127310 - 0913018766)
  </div>

</div>

