{# ===========================
   Customer Statement - PDF
   FIX 1: النوع reads from LMT Debt Collection
   FIX 2: ns.running scope fix
   FIX 3: POS shows bank account name (بطاقة الاسلامي etc.)
   =========================== #}

{% set from_date = "2000-01-01" %}
{% set to_date = (frappe.form_dict.get("to_date") or frappe.utils.nowdate()) %}

{% set party1 = (doc.customer_name or doc.name or "") %}
{% set party2 = (doc.name or doc.customer_name or "") %}

{% set company      = frappe.db.get_default("company") %}
{% set company_logo = frappe.db.get_value("Company", company, "company_logo") %}
{% set currency     = frappe.db.get_value("Company", company, "default_currency") %}

{% set gl_rows = frappe.db.sql("""
  SELECT
    posting_date, account, debit, credit,
    voucher_type, voucher_no, remarks, is_opening,
    (debit - credit) AS net
  FROM `tabGL Entry`
  WHERE docstatus=1 AND is_cancelled=0
    AND party_type='Customer'
    AND party IN (%s, %s)
    AND posting_date BETWEEN %s AND %s
  ORDER BY posting_date ASC, creation ASC
""", (party1, party2, from_date, to_date), as_dict=True) %}

{% set debt_rows = frappe.db.sql("""
  SELECT receipt_no, payment_type, mode_of_payment, name, bank
  FROM `tabLMT Debt Collection`
  WHERE docstatus < 2
    AND customer IN (%s, %s)
""", (party1, party2), as_dict=True) %}

{% set PAYMENT_DISPLAY = {
  "Cash":             "نقد",
  "Cheque":           "صك",
  "Bank Draft":       "صك",
  "Wire Transfer":    "تحويل",
  "POS terminal":     "ماكينة نقاط بيع",
  "Credit Card":      "تحويل",
  "نقد":              "نقد",
  "صك":               "صك",
  "تحويل":            "تحويل",
  "ماكينة نقاط بيع": "ماكينة نقاط بيع"
} %}

{% set ns = namespace(
    calc_opening   = 0.0,
    calc_movement  = 0.0,
    total_sale     = 0.0,
    total_collect  = 0.0,
    running        = 0.0,
    debt_map       = {}
) %}

{# Build debt_map — POS: use bank field, strip " - XX" suffix #}
{% for d in debt_rows %}
  {% set raw = (d.payment_type or d.mode_of_payment or "") %}
  {% if raw == "ماكينة نقاط بيع" or raw == "POS terminal" %}
    {% set bank_raw = (d.bank or "ماكينة نقاط بيع") %}
    {% set label = bank_raw.rsplit(" - ", 1)[0].strip() %}
  {% else %}
    {% set label = PAYMENT_DISPLAY.get(raw, raw) %}
  {% endif %}
  {% if d.receipt_no %}
    {% set _ = ns.debt_map.update({ (d.receipt_no)|string : label }) %}
  {% endif %}
  {% set _ = ns.debt_map.update({ (d.name)|string : label }) %}
{% endfor %}

{% set sql_opening = frappe.db.sql("""
  SELECT IFNULL(SUM(debit - credit), 0) AS opening
  FROM `tabGL Entry`
  WHERE docstatus=1 AND is_cancelled=0
    AND party_type='Customer'
    AND party IN (%s, %s)
    AND posting_date < %s
""", (party1, party2, from_date), as_dict=True)[0] %}

{% set ns.calc_opening = (sql_opening.opening or 0) | float %}

{% for r in gl_rows %}
  {% set net        = (r.net or 0) | float %}
  {% set remark_low = (r.remarks or "")|string|lower %}
  {% if r.is_opening == "Yes" or r.is_opening == 1 or "migration" in remark_low or "opening" in remark_low or "افتتاحي" in remark_low %}
    {% set ns.calc_opening = ns.calc_opening + net %}
  {% else %}
    {% set ns.calc_movement = ns.calc_movement + net %}
  {% endif %}
{% endfor %}

{% set closing = ns.calc_opening + ns.calc_movement %}

