{# LMT Legacy Customer Statement #}
{% set from_date = "2022-01-01" %}
{% set to_date = frappe.utils.nowdate() %}
{% set company      = frappe.db.get_default("company") %}
{% set company_logo = frappe.db.get_value("Company", company, "company_logo") %}
{% set currency     = frappe.db.get_value("Company", company, "default_currency") %}
{% set cust_key = doc.custom_txt_1 or "" %}

{% set lmt_cust = frappe.db.sql("""
  SELECT customer_name, agent_name, location
  FROM `tabLMT Customer` WHERE lmt_key = %s LIMIT 1
""", (cust_key,), as_dict=True) %}
{% set lmt_info = lmt_cust[0] if lmt_cust else {} %}
{% set am = doc.account_manager %}
{% set agent_display = lmt_info.get("agent_name", "") %}
{% if not agent_display and am %}
  {% set agent_display = frappe.db.get_value("User", am, "full_name") or am %}
{% endif %}
{% set location = lmt_info.get("location", "") or doc.customer_primary_address or "غير محدد" %}

{% set orders = frappe.db.sql("""
  SELECT order_date as date, invoice as ref, trans_type,
         total_cost as amount, lmt_order_id as id
  FROM `tabLMT Order`
  WHERE customer_key = %s AND order_status = 'Complete'
  ORDER BY order_date ASC, creation ASC
""", (cust_key,), as_dict=True) %}

{% set payments = frappe.db.sql("""
  SELECT date, received, COALESCE(custom_settlement_discount,0) as disc,
         receipt_number as ref, trans_type as pay_type
  FROM `tabLMT Payment`
  WHERE customer_key = %s
  ORDER BY date ASC, creation ASC
""", (cust_key,), as_dict=True) %}

{% set ns = namespace(
    rows=[],
    running=0.0,
    total_sale=0.0,
    total_return=0.0,
    total_collect=0.0,
    total_discount=0.0,
    total_opening=0.0
) %}

{% for o in orders %}
  {% set amt = (o.amount or 0)|float %}
  {% if o.trans_type == "ترجيع" %}
    {# FIX: total_cost is already negative — use abs for credit #}
    {% set _ = ns.rows.append({"date": o.date, "ref": o.ref or o.id or "", "trans_type": "ترجيع", "debit": 0.0, "credit": amt|abs, "discount": 0.0, "row_class": "return-row", "sort_key": o.date|string + "A"}) %}
  {% else %}
    {% set _ = ns.rows.append({"date": o.date, "ref": o.ref or o.id or "", "trans_type": o.trans_type or "بيع", "debit": amt, "credit": 0.0, "discount": 0.0, "row_class": "", "sort_key": o.date|string + "A"}) %}
  {% endif %}
{% endfor %}

{% for p in payments %}
  {% set recv = (p.received or 0)|float %}
  {% set disc = (p.disc or 0)|float %}
  {% set ref = p.ref or "" %}
  {% if recv < 0 or ref == "0" %}
    {% set opening_amt = (recv * -1) if recv < 0 else recv %}
    {% set _ = ns.rows.append({"date": p.date, "ref": "الديون السابقة", "trans_type": "الديون السابقة", "debit": opening_amt, "credit": 0.0, "discount": 0.0, "row_class": "opening-row", "sort_key": p.date|string + "A"}) %}
  {% elif recv > 0 or disc > 0 %}
    {% set _ = ns.rows.append({"date": p.date, "ref": ref, "trans_type": "credit", "debit": 0.0, "credit": recv, "discount": disc, "row_class": "", "sort_key": p.date|string + "B"}) %}
  {% endif %}
{% endfor %}

{% set sorted_rows = ns.rows | sort(attribute='sort_key') %}

{% for r in sorted_rows %}
  {% if r.trans_type == "الديون السابقة" %}
    {% set ns.total_opening = ns.total_opening + r.debit %}
  {% elif r.trans_type == "ترجيع" %}
    {% set ns.total_return = ns.total_return + r.credit %}
  {% elif r.debit > 0 %}
    {% set ns.total_sale = ns.total_sale + r.debit %}
  {% endif %}
  {% if r.trans_type == "credit" %}
    {% if r.credit > 0 %}{% set ns.total_collect = ns.total_collect + r.credit %}{% endif %}
    {% if r.discount > 0 %}{% set ns.total_discount = ns.total_discount + r.discount %}{% endif %}
  {% endif %}
{% endfor %}

{% set net_sale = ns.total_sale - ns.total_return %}
{% set final_balance = ns.total_opening + net_sale - ns.total_collect - ns.total_discount %}

<style>
  @page { size: A4 landscape; margin: 10mm; }
