  .sum { margin-top: 8px; width: 100%; border-collapse: collapse; border: 2px solid #000; }
  .sum td { border: 1px solid #000; padding: 8px; font-weight: 900; font-size: 11px; text-align: center; background: #eee; -webkit-print-color-adjust: exact; }
  .footer { text-align: center; margin-top: 14px; font-size: 10px; border-top: 1px solid #000; padding-top: 8px; }
</style>

<div class="print-format">
  <div class="hdr">
    {% if company_logo %}<img class="header-logo" src="{{ frappe.utils.get_url() }}{{ company_logo }}">{% endif %}
    <div style="font-size:18px;font-weight:900;text-decoration:underline;">كشف حساب الزبون</div>
    <div class="meta">من: {{ frappe.utils.formatdate(from_date) }} — إلى: {{ frappe.utils.formatdate(to_date) }}</div>
    <div class="meta">تاريخ إصدار الكشف: {{ frappe.utils.formatdate(frappe.utils.nowdate()) }}</div>
  </div>

  <table class="info">
    <tr>
      <td style="width:55%;"><div class="box" style="text-align:right">
        <div><strong>الزبون:</strong> {{ doc.customer_name or doc.name }}</div>
        <div><strong>المندوب:</strong> {{ agent_display or "غير محدد" }}</div>
        <div><strong>العنوان:</strong> {{ location }}</div>
      </div></td>
      <td style="width:45%;"><div class="box">
        <div><strong>الرصيد الافتتاحي:</strong> <span class="num">{{ frappe.utils.fmt_money(ns.total_opening, currency=currency) }}</span></div>
        <div><strong>صافي البيع:</strong> <span class="num">{{ frappe.utils.fmt_money(net_sale, currency=currency) }}</span></div>
        <div><strong>الرصيد النهائي:</strong> <span class="num">{{ frappe.utils.fmt_money(final_balance, currency=currency) }}</span></div>
      </div></td>
    </tr>
  </table>

  <table class="tbl">
    <colgroup>
      <col style="width:9%"><col style="width:13%"><col style="width:11%">
      <col style="width:8%"><col style="width:11%"><col style="width:10%"><col style="width:9%"><col style="width:11%">
    </colgroup>
    <thead>
      <tr>
        <th>التاريخ</th><th>رقم الفاتورة</th><th>البيع</th>
        <th>الايصال</th><th>التحصيل</th><th>خصم تسوية</th><th>النوع</th><th>الرصيد</th>
      </tr>
    </thead>
    <tbody>
      {% set ns.running = 0.0 %}
      {% for r in sorted_rows %}
        {% set ns.running = ns.running + r.debit - r.credit - r.discount %}
        <tr{% if r.row_class %} class="{{ r.row_class }}"{% endif %}>
          <td>{{ frappe.utils.formatdate(r.date) }}</td>
          <td>{{ r.ref }}</td>
          <td>{% if r.debit > 0 %}{{ frappe.utils.fmt_money(r.debit, currency=currency) }}{% endif %}</td>
          <td>{% if r.credit > 0 or r.discount > 0 %}{{ r.ref }}{% endif %}</td>
          <td>{% if r.credit > 0 %}{{ frappe.utils.fmt_money(r.credit, currency=currency) }}{% endif %}</td>
          <td>{% if r.discount > 0 %}<span class="disc-cell">{{ frappe.utils.fmt_money(r.discount, currency=currency) }}</span>{% endif %}</td>
          <td>{{ r.trans_type }}</td>
          <td><strong>{{ frappe.utils.fmt_money(ns.running, currency=currency) }}</strong></td>
        </tr>
      {% endfor %}
      {% if sorted_rows|length == 0 %}
        <tr><td colspan="8" style="padding:14px;text-align:center;">لا توجد بيانات</td></tr>
      {% endif %}
    </tbody>
  </table>

  <table class="sum">
    <tr>
      <td>مجموع البيع: {{ frappe.utils.fmt_money(ns.total_sale, currency=currency) }}</td>
      {% if ns.total_return > 0 %}<td>مجموع الترجيع: {{ frappe.utils.fmt_money(ns.total_return, currency=currency) }}</td>{% endif %}
      <td>مجموع التحصيل: {{ frappe.utils.fmt_money(ns.total_collect, currency=currency) }}</td>
      {% if ns.total_discount > 0 %}<td class="disc-cell">مجموع الخصم: {{ frappe.utils.fmt_money(ns.total_discount, currency=currency) }}</td>{% endif %}
      <td>الرصيد النهائي: {{ frappe.utils.fmt_money(final_balance, currency=currency) }}</td>
    </tr>
  </table>

  <div class="footer">للاستفسار الاتصال على الأرقام التالية : (0926127310 - 0913018766)</div>
</div>
